12	-- the terms contained in the LICENSE.txt file.
13	-------------------------------------------------------------------------------
14	
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.std_logic_unsigned.all;
18	use ieee.std_logic_arith.all;
19	
20	library surf;
21	use surf.StdRtlPkg.all;
22	use surf.AxiStreamPkg.all;
23	
24	package EthMacPkg is
25	
26	   -- Default MAC is 08:00:56:00:00:00
27	   constant MAC_ADDR_INIT_C : slv(47 downto 0) := x"000000560008";
28	
29	   -- EtherTypes
30	   constant ARP_TYPE_C  : slv(15 downto 0) := x"0608";  -- EtherType = ARP = 0x0806
31	   constant IPV4_TYPE_C : slv(15 downto 0) := x"0008";  -- EtherType = IPV4 = 0x0800
32	
33	   -- IPV4 Protocol Constants
34	   constant UDP_C  : slv(7 downto 0) := x"11";  -- Protocol = UDP  = 0x11
35	   constant TCP_C  : slv(7 downto 0) := x"06";  -- Protocol = TCP  = 0x06
36	   constant ICMP_C : slv(7 downto 0) := x"01";  -- Protocol = ICMP = 0x01
37	   constant IGMP_C : slv(7 downto 0) := x"02";  -- Protocol = IGMP = 0x02
38	
39	   -- DHCP Constants
40	   constant DHCP_CPORT : slv(15 downto 0) := x"4400";  -- Port = 68 = 0x0044
41	   constant DHCP_SPORT : slv(15 downto 0) := x"4300";  -- Port = 67 = 0x0043
42	
43	   -- First TUSER Bits
44	   constant EMAC_FRAG_BIT_C : integer := 0;
45	   constant EMAC_SOF_BIT_C  : integer := 1;
46	
47	   -- Last TUSER Bits
48	   constant EMAC_EOFE_BIT_C   : integer := 0;
49	   constant EMAC_IPERR_BIT_C  : integer := 1;
50	   constant EMAC_TCPERR_BIT_C : integer := 2;
51	   constant EMAC_UDPERR_BIT_C : integer := 3;
52	
53	   -- Ethernet AXI Stream Configuration
54	   constant EMAC_AXIS_CONFIG_C : AxiStreamConfigType := (
55	      -- TDEST_INTERLEAVE_C => false,
56	      TSTRB_EN_C    => false,
57	      TDATA_BYTES_C => 16,
58	      TDEST_BITS_C  => 8,
59	      TID_BITS_C    => 0,
60	      TKEEP_MODE_C  => TKEEP_COMP_C,
61	      TUSER_BITS_C  => 4,
62	      TUSER_MODE_C  => TUSER_FIRST_LAST_C);
63	
64	   -- Ethernet AXI Stream Configuration that's optimized for 141-bit FIFO interface (2 x 72b input BRAMs)
65	   constant INT_EMAC_AXIS_CONFIG_C : AxiStreamConfigType := (
66	      -- TDEST_INTERLEAVE_C => EMAC_AXIS_CONFIG_C.TDEST_INTERLEAVE_C,
67	      TSTRB_EN_C    => EMAC_AXIS_CONFIG_C.TSTRB_EN_C,
68	      TDATA_BYTES_C => EMAC_AXIS_CONFIG_C.TDATA_BYTES_C,
69	      TDEST_BITS_C  => 0,  -- TDEST not used internally of EthMacTop.vhd
70	      TID_BITS_C    => EMAC_AXIS_CONFIG_C.TID_BITS_C,
71	      TKEEP_MODE_C  => EMAC_AXIS_CONFIG_C.TKEEP_MODE_C,
72	      TUSER_BITS_C  => EMAC_AXIS_CONFIG_C.TUSER_BITS_C,
73	      TUSER_MODE_C  => EMAC_AXIS_CONFIG_C.TUSER_MODE_C);
74	
75	   -- Generic XMAC Configuration
76	   type EthMacConfigType is record
77	      macAddress  : slv(47 downto 0);
78	      filtEnable  : sl;
79	      pauseEnable : sl;
80	      pauseTime   : slv(15 downto 0);
81	      pauseThresh : slv(15 downto 0);
82	      ipCsumEn    : sl;
83	      tcpCsumEn   : sl;
84	      udpCsumEn   : sl;
85	      dropOnPause : sl;
86	   end record EthMacConfigType;
87	   constant ETH_MAC_CONFIG_INIT_C : EthMacConfigType := (
88	      macAddress  => MAC_ADDR_INIT_C,
89	      filtEnable  => '1',
90	      pauseEnable => '1',
91	      pauseTime   => x"00FF",
92	      pauseThresh => toSlv((9000/16), 16),  -- 9000B jumbo frame in cache
93	      ipCsumEn    => '1',
94	      tcpCsumEn   => '1',
95	      udpCsumEn   => '1',
96	      dropOnPause => '0');
97	   type EthMacConfigArray is array (natural range<>) of EthMacConfigType;
98	
99	   -- Generic XMAC Status
100	   type EthMacStatusType is record
101	      rxFifoDropCnt : sl;
102	      rxPauseCnt    : sl;
103	      txPauseCnt    : sl;
104	      rxCountEn     : sl;
105	      rxOverFlow    : sl;
106	      rxCrcErrorCnt : sl;
107	      txCountEn     : sl;
108	      txUnderRunCnt : sl;
109	      txNotReadyCnt : sl;
110	   end record EthMacStatusType;
111	   constant ETH_MAC_STATUS_INIT_C : EthMacStatusType := (
112	      rxFifoDropCnt => '0',
113	      rxPauseCnt    => '0',
114	      txPauseCnt    => '0',
115	      rxCountEn     => '0',
116	      rxOverFlow    => '0',
117	      rxCrcErrorCnt => '0',
118	      txCountEn     => '0',
119	      txUnderRunCnt => '0',
120	      txNotReadyCnt => '0');
121	   type EthMacStatusArray is array (natural range<>) of EthMacStatusType;
122	
123	   constant EMAC_CSUM_PIPELINE_C : natural := 3;
124	   type EthMacCsumAccumType is record
125	      step : slv(EMAC_CSUM_PIPELINE_C downto 0);
126	      sum1 : Slv32Array(1 downto 0);
127	      sum3 : slv(31 downto 0);
128	      sum5 : slv(15 downto 0);
129	   end record EthMacCsumAccumType;
130	   constant ETH_MAC_CSUM_ACCUM_INIT_C : EthMacCsumAccumType := (
131	      step => (others => '0'),
132	      sum1 => (others => (others => '0')),
133	      sum3 => (others => '0'),
134	      sum5 => (others => '0'));
135	   type EthMacCsumAccumArray is array (natural range<>) of EthMacCsumAccumType;
136	
137	   function EthPortArrayBigEndian (portNum : PositiveArray; portSize : positive) return Slv16Array;
138	
139	   procedure getEthMacCsum (
140	      -- Input
141	      udpDet  : in    sl;
142	      last    : in    sl;
143	      hdr     : in    Slv8Array(19 downto 0);  -- IPv4 Header
144	      tKeep   : in    slv(15 downto 0);        -- TCP/Data tKeep
145	      tData   : in    slv(127 downto 0);       -- TCP/Data tKeep
146	      len     : in    slv(15 downto 0);
147	      ibcsum  : in    slv(15 downto 0);        -- TCP/UDP checksum to compare
148	      -- Summation/Accumulation Signals
149	      r       : in    EthMacCsumAccumArray(1 downto 0);
150	      v       : inout EthMacCsumAccumArray(1 downto 0);
151	      -- Results
152	      ipValid : inout sl;
153	      ipCsum  : inout slv(15 downto 0);
154	      valid   : inout sl;
155	      csum    : inout slv(15 downto 0));
156	
157	end package EthMacPkg;
158	
159	package body EthMacPkg is
160	
161	   function EthPortArrayBigEndian (portNum : PositiveArray; portSize : positive) return Slv16Array is
162	      variable vec    : slv(15 downto 0);
163	      variable retVar : Slv16Array((portSize-1) downto 0);
164	   begin
165	      for i in (portSize-1) downto 0 loop
166	         -- Convert the NaturalArray into 16-bit SLV
167	         vec                    := toSlv(portNum(i), 16);
168	         -- Convert to big Endian
169	         retVar(i)(15 downto 8) := vec(7 downto 0);
170	         retVar(i)(7 downto 0)  := vec(15 downto 8);
171	      end loop;
172	      return retVar;
173	   end function;
174	
175	   procedure getEthMacCsum (
176	      -- Input
177	      udpDet  : in    sl;
178	      last    : in    sl;
179	      hdr     : in    Slv8Array(19 downto 0);  -- IPv4 Header
180	      tKeep   : in    slv(15 downto 0);        -- TCP/Data tKeep
181	      tData   : in    slv(127 downto 0);       -- TCP/Data tData
182	      len     : in    slv(15 downto 0);        -- TCP/Data length
183	      ibcsum  : in    slv(15 downto 0);        -- TCP/UDP checksum to compare
184	      -- Summation/Accumulation Signals
185	      r       : in    EthMacCsumAccumArray(1 downto 0);
186	      v       : inout EthMacCsumAccumArray(1 downto 0);
187	      -- Results
188	      ipValid : inout sl;
189	      ipCsum  : inout slv(15 downto 0);
190	      valid   : inout sl;
191	      csum    : inout slv(15 downto 0)) is
192	      variable header  : Slv32Array(9 downto 0);
193	      variable data    : Slv32Array(7 downto 0);
194	      variable hdrCsum : slv(15 downto 0);
195	      variable lenProt : slv(31 downto 0);
196	      variable sum0A   : Slv32Array(3 downto 0);
197	      variable sum0B   : Slv32Array(3 downto 0);
198	      variable sum2A   : Slv32Array(1 downto 0);
199	      variable sum2B   : slv(31 downto 0);
200	      variable sum3    : Slv32Array(1 downto 0);
201	      variable sum3A   : Slv32Array(1 downto 0);
202	      variable sum3B   : Slv32Array(1 downto 0);
203	      variable sum4    : Slv32Array(1 downto 0);
204	   begin
205	      -- Convert to 32-bit (little Endian) words
206	      lenProt := x"0000" & len;
207	      for i in 9 downto 0 loop
208	         header(i) := x"00000000";
209	         -- Check for inbound checksum
210	         if i = 5 then
211	            -- Mask off and Save Header Checksum
212	            hdrCsum(15 downto 8) := hdr(2*i+0);
213	            hdrCsum(7 downto 0)  := hdr(2*i+1);
214	         else
215	            header(i)(15 downto 8) := hdr(2*i+0);
216	            header(i)(7 downto 0)  := hdr(2*i+1);
217	         end if;
218	      end loop;
219	      for i in 7 downto 0 loop
220	         data(i) := x"00000000";
221	         -- Check tKeep for big Endian upper byte of 16-bit word
222	         if tKeep((2*i)+0) = '1' then
223	            data(i)(15 downto 8) := tData((8*((2*i)+0))+7 downto (8*((2*i)+0))+0);
224	         end if;
225	         -- Check tKeep for big Endian lower byte of 16-bit word
226	         if tKeep((2*i)+1) = '1' then
227	            data(i)(7 downto 0) := tData((8*((2*i)+1))+7 downto (8*((2*i)+1))+0);
228	         end if;
229	      end loop;
230	
231	      -- Summation: Level0
232	      v(0).step(0) := last;
233	      v(1).step(0) := last;
234	      for i in 3 downto 0 loop
235	         sum0A(i) := header(2*i+0) + header(2*i+1);
236	         sum0B(i) := data(2*i+0) + data(2*i+1);
237	      end loop;
238	
239	      -- Summation: Level1
240	      for i in 1 downto 0 loop
241	         v(0).sum1(i) := sum0A(2*i+0) + sum0A(2*i+1);
242	         v(1).sum1(i) := sum0B(2*i+0) + sum0B(2*i+1);
243	      end loop;
244	
245	      -- Summation: Level2
246	      v(0).step(1) := r(0).step(0);
247	      v(1).step(1) := r(1).step(0);
248	      sum2A(0)     := r(0).sum1(0) + r(0).sum1(1);
249	      sum2A(1)     := header(8) + header(9);
250	      sum2B        := r(1).sum1(0) + r(1).sum1(1);
251	
252	      -- Summation: Level3
253	      v(0).sum3 := sum2A(0) + sum2A(1);
254	
255	      -- Check if we need to reset the accumulator
256	      if r(0).step(1) = '1' then
257	         v(1).sum3 := (others => '0');
258	      else
259	         -- Summation/Accumulation: Level3
260	         v(1).sum3 := r(1).sum3 + sum2B;
261	      end if;
262	
263	      -- Summation: Level4
264	      v(0).step(2) := r(0).step(1);
265	      v(1).step(2) := r(1).step(1);
266	      sum3(0)      := r(0).sum3;
267	      sum3(1)      := r(1).sum3 + lenProt;
268	      for i in 1 downto 0 loop
269	         sum3A(i)(31 downto 16) := x"0000";
270	         sum3A(i)(15 downto 0)  := sum3(i)(31 downto 16);
271	         sum3B(i)(31 downto 16) := x"0000";
272	         sum3B(i)(15 downto 0)  := sum3(i)(15 downto 0);
273	         sum4(i)                := sum3A(i) + sum3B(i);
274	      end loop;
275	
276	      -- Summation: Level5
277	      for i in 1 downto 0 loop
278	         v(i).sum5 := sum4(i)(31 downto 16) + sum4(i)(15 downto 0);
279	      end loop;
280	
281	      -- Perform 1's complement
282	      v(0).step(3) := r(0).step(2);
283	      v(1).step(3) := r(1).step(2);
284	      ipCsum       := not(r(0).sum5);
285	      csum         := not(r(1).sum5);
286	
287	      -- UDP checksum is calculated using one's complement arithmetic (RFC 793).
288	      -- UDP has a special case where 0x0000 is reserved for "no checksum computed".
289	      -- Thus 0x0000 is illegal and when calculated following the standard
290	      -- algorithm, replaced with 0xFFFF.
291	      if (udpDet = '1') and (csum = x"0000") then
292	         csum := x"FFFF";
293	      end if;
294	
295	      -- Check for valid inbound checksum
296	      if (ipCsum = hdrCsum) then
297	         ipValid := '1';
298	      else
299	         ipValid := '0';
300	      end if;
301	
302	      -- Check for UDP special case of 0x0000 checksum
303	      if (udpDet = '1') and (ibcsum = x"0000") then
304	         valid := '1';
305	      -- check the standard checksum calculation
306	      elsif (ibcsum = csum) then
307	         valid := '1';
308	      -- Else not a valid checksum
309	      else
310	         valid := '0';
311	      end if;
312	
313	   end procedure;
314	
315	end package body EthMacPkg;
