60	      mAxisMaster => AXI_STREAM_MASTER_INIT_C);
61	
62	   signal r   : RegType := REG_INIT_C;
63	   signal rin : RegType;
64	
65	   -- attribute dont_touch      : string;
66	   -- attribute dont_touch of r : signal is "true";
67	
