69	
70	   U_FiltEnGen : if (FILT_EN_G = true) generate
71	
72	      comb : process (dropOnPause, ethRst, filtEnable, mAxisCtrl, macAddress,
73	                      r, sAxisMaster) is
74	         variable v : RegType;
75	      begin
76	         -- Latch the current value
77	         v := r;
78	
79	         -- Move the data
80	         v.mAxisMaster := sAxisMaster;
81	
82	         -- State Machine
83	         case r.state is
84	            ----------------------------------------------------------------------
85	            when IDLE_S =>
86	               -- Check for data
87	               if (sAxisMaster.tValid = '1') then
88	                  -- Drop frames when pause is asserted to avoid downstream errors
89	                  if (mAxisCtrl.pause = '1') and (dropOnPause = '1') then
90	                     -- Drop the packet
91	                     v.mAxisMaster.tValid := '0';
92	                     -- Check for no EOF
93	                     if (sAxisMaster.tLast = '0') then
94	                        -- Next State
95	                        v.state := DROP_S;
96	                     end if;
97	                  -- Local match, broadcast or multicast
98	                  elsif (filtEnable = '0') or
99	                     (sAxisMaster.tData(47 downto 0) = macAddress) or  -- Local
100	                     (sAxisMaster.tData(0) = '1') or  -- Multicast
101	                     (sAxisMaster.tData(47 downto 0) = x"FFFFFFFFFFFF") then  -- Broadcast
102	                     -- Check for no EOF
103	                     if (sAxisMaster.tLast = '0') then
104	                        -- Next State
105	                        v.state := PASS_S;
106	                     end if;
107	                  -- Drop frame
108	                  else
109	                     -- Drop the packet
110	                     v.mAxisMaster.tValid := '0';
111	                     -- Check for no EOF
112	                     if (sAxisMaster.tLast = '0') then
113	                        -- Next State
114	                        v.state := DROP_S;
115	                     end if;
116	                  end if;
117	               end if;
118	            ----------------------------------------------------------------------
119	            when DROP_S =>
120	               -- Drop the packet
121	               v.mAxisMaster.tValid := '0';
122	               -- Check for a valid EOF
123	               if (sAxisMaster.tValid = '1') and (sAxisMaster.tLast = '1') then
124	                  -- Next State
125	                  v.state := IDLE_S;
126	               end if;
127	            ----------------------------------------------------------------------
128	            when PASS_S =>
129	               -- Check for a valid EOF
130	               if (sAxisMaster.tValid = '1') and (sAxisMaster.tLast = '1') then
131	                  -- Next State
132	                  v.state := IDLE_S;
133	               end if;
134	         ----------------------------------------------------------------------
135	         end case;
136	
137	         -- Reset
138	         if (RST_ASYNC_G = false and ethRst = RST_POLARITY_G) then
139	            v := REG_INIT_C;
140	         end if;
141	
142	         -- Register the variable for next clock cycle
143	         rin <= v;
144	
145	         -- Outputs
146	         mAxisMaster <= r.mAxisMaster;
147	
148	      end process;
149	
150	      seq : process (ethClk, ethRst) is
151	      begin
152	         if (RST_ASYNC_G and ethRst = RST_POLARITY_G) then
153	            r <= REG_INIT_C after TPD_G;
154	         elsif rising_edge(ethClk) then
155	            r <= rin after TPD_G;
156	         end if;
157	      end process seq;
158	
159	   end generate;
160	
161	   U_FiltDisGen : if (FILT_EN_G = false) generate
162	      mAxisMaster <= sAxisMaster;
163	   end generate;
164	
165	end rtl;
