1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description: RX Checksum Hardware Offloading Engine
5	-- https://docs.google.com/spreadsheets/d/1_1M1keasfq8RLmRYHkO0IlRhMq5YZTgJ7OGrWvkib8I/edit?usp=sharing
6	-------------------------------------------------------------------------------
7	-- This file is part of 'SLAC Firmware Standard Library'.
8	-- It is subject to the license terms in the LICENSE.txt file found in the
9	-- top-level directory of this distribution and at:
10	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
11	-- No part of 'SLAC Firmware Standard Library', including this file,
12	-- may be copied, modified, propagated, or distributed except according to
13	-- the terms contained in the LICENSE.txt file.
14	-------------------------------------------------------------------------------
15	
16	library ieee;
17	use ieee.std_logic_1164.all;
18	use ieee.std_logic_arith.all;
19	use ieee.std_logic_unsigned.all;
20	
21	library surf;
22	use surf.StdRtlPkg.all;
23	use surf.AxiStreamPkg.all;
24	use surf.EthMacPkg.all;
25	
26	entity EthMacRxCsum is
27	   generic (
28	      TPD_G          : time    := 1 ns;
29	      RST_POLARITY_G : sl      := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
30	      RST_ASYNC_G    : boolean := false;
31	      JUMBO_G        : boolean := true;
32	      ROCEV2_EN_G    : boolean := false);
33	   port (
34	      -- Clock and Reset
35	      ethClk      : in  sl;
36	      ethRst      : in  sl;
37	      -- Configurations
38	      ipCsumEn    : in  sl;
39	      tcpCsumEn   : in  sl;
40	      udpCsumEn   : in  sl;
41	      -- Inbound data from MAC
42	      sAxisMaster : in  AxiStreamMasterType;
43	      mAxisMaster : out AxiStreamMasterType);
44	end EthMacRxCsum;
45	
46	architecture rtl of EthMacRxCsum is
47	
48	   constant MAX_FRAME_SIZE_C : natural := ite(JUMBO_G, 9000, 1500);
49	
50	   type StateType is (
51	      IDLE_S,
52	      IPV4_HDR0_S,
53	      IPV4_HDR1_S,
54	      MOVE_S,
55	      BLOWOFF_S);
56	
57	   type RegType is record
58	      valid        : slv(1 downto 0);
59	      fragDet      : slv(EMAC_CSUM_PIPELINE_C+1 downto 0);
60	      eofeDet      : slv(EMAC_CSUM_PIPELINE_C+1 downto 0);
61	      ipv4Det      : slv(EMAC_CSUM_PIPELINE_C+1 downto 0);
62	      udpDet       : slv(EMAC_CSUM_PIPELINE_C+1 downto 0);
63	      tcpDet       : slv(EMAC_CSUM_PIPELINE_C+1 downto 0);
64	      tcpFlag      : sl;
65	      pipeFlush    : sl;
66	      byteCnt      : natural range 0 to (MAX_FRAME_SIZE_C + 32);  -- MTU size + padding
67	      ipv4Hdr      : Slv8Array(19 downto 0);
68	      ipv4Len      : Slv16Array(EMAC_CSUM_PIPELINE_C+1 downto 0);
69	      protLen      : Slv16Array(EMAC_CSUM_PIPELINE_C+1 downto 0);
70	      protCsum     : Slv16Array(EMAC_CSUM_PIPELINE_C+1 downto 0);
71	      roce         : slv(EMAC_CSUM_PIPELINE_C+1 downto 0);
72	      calc         : EthMacCsumAccumArray(1 downto 0);
73	      tKeep        : slv(15 downto 0);
74	      tData        : slv(127 downto 0);
75	      mAxisMaster  : AxiStreamMasterType;
76	      mAxisMasters : AxiStreamMasterArray(EMAC_CSUM_PIPELINE_C+1 downto 0);
77	      state        : StateType;
78	   end record RegType;
79	   constant REG_INIT_C : RegType := (
80	      valid        => (others => '0'),
81	      fragDet      => (others => '0'),
82	      eofeDet      => (others => '0'),
83	      ipv4Det      => (others => '0'),
84	      udpDet       => (others => '0'),
85	      tcpDet       => (others => '0'),
86	      tcpFlag      => '0',
87	      pipeFlush    => '0',
88	      byteCnt      => 0,
89	      ipv4Hdr      => (others => (others => '0')),
90	      ipv4Len      => (others => (others => '0')),
91	      protLen      => (others => (others => '0')),
92	      protCsum     => (others => (others => '0')),
93	      roce         => (others => '0'),
94	      calc         => (others => ETH_MAC_CSUM_ACCUM_INIT_C),
95	      tKeep        => (others => '0'),
96	      tData        => (others => '0'),
97	      mAxisMaster  => AXI_STREAM_MASTER_INIT_C,
98	      mAxisMasters => (others => AXI_STREAM_MASTER_INIT_C),
99	      state        => IDLE_S);
100	
101	   signal r   : RegType := REG_INIT_C;
102	   signal rin : RegType;
103	
104	   signal dbg : Slv16Array(1 downto 0);
105	
106	   -- attribute dont_touch      : string;
107	   -- attribute dont_touch of r : signal is "TRUE";
108	
109	begin
110	
111	   comb : process (ethRst, ipCsumEn, r, sAxisMaster, tcpCsumEn, udpCsumEn) is
112	      variable v     : RegType;
113	      variable dummy : Slv16Array(1 downto 0);
114	   begin
115	      -- Latch the current value
116	      v := r;
117	
118	      GetEthMacCsum (
119	         r.udpDet(EMAC_CSUM_PIPELINE_C),
120	         r.mAxisMaster.tLast,
121	         r.ipv4Hdr,
122	         r.tKeep,
123	         r.tData,
124	         r.protLen(EMAC_CSUM_PIPELINE_C-1),
125	         r.protCsum(EMAC_CSUM_PIPELINE_C),
126	         r.calc,
127	         v.calc,
128	         v.valid(0),
129	         dummy(0),                      -- Unused in RX CSUM
130	         v.valid(1),
131	         dummy(1));                     -- Unused in RX CSUM
132	
133	      -- Reset the flags
134	      v.tKeep                                       := (others => '0');
135	      v.mAxisMaster.tValid                          := '0';
136	      v.mAxisMaster.tLast                           := '0';
137	      v.mAxisMasters(EMAC_CSUM_PIPELINE_C+1).tValid := '0';
138	
139	      -- Check if we need to update the pipeline
140	      if (r.mAxisMaster.tValid = '1') or (r.state = IDLE_S) or (r.pipeFlush = '1') then
141	         v.mAxisMasters := r.mAxisMasters(EMAC_CSUM_PIPELINE_C downto 0) & r.mAxisMaster;
142	         v.fragDet      := r.fragDet(EMAC_CSUM_PIPELINE_C downto 0) & r.fragDet(0);
143	         v.eofeDet      := r.eofeDet(EMAC_CSUM_PIPELINE_C downto 0) & r.eofeDet(0);
144	         v.ipv4Det      := r.ipv4Det(EMAC_CSUM_PIPELINE_C downto 0) & r.ipv4Det(0);
145	         v.udpDet       := r.udpDet(EMAC_CSUM_PIPELINE_C downto 0) & r.udpDet(0);
146	         v.tcpDet       := r.tcpDet(EMAC_CSUM_PIPELINE_C downto 0) & r.tcpDet(0);
147	         v.ipv4Len      := r.ipv4Len(EMAC_CSUM_PIPELINE_C downto 0) & r.ipv4Len(0);
148	         v.protLen      := r.protLen(EMAC_CSUM_PIPELINE_C downto 0) & r.protLen(0);
149	         v.protCsum     := r.protCsum(EMAC_CSUM_PIPELINE_C downto 0) & r.protCsum(0);
150	         v.roce         := r.roce(EMAC_CSUM_PIPELINE_C downto 0) & r.roce(0);
151	      end if;
152	
153	      -- Check for tLast in pipeline
154	      if (v.mAxisMasters(EMAC_CSUM_PIPELINE_C+1).tLast = '1') then
155	         -- Stop flushing the pipeline when last word exits
156	         v.pipeFlush := '0';
157	         -- Check if IPv4 is detected and being checked
158	         if (r.ipv4Det(EMAC_CSUM_PIPELINE_C+1) = '1') and (ipCsumEn = '1') then
159	            -- Forward the result of checksum calculation
160	            axiStreamSetUserBit(INT_EMAC_AXIS_CONFIG_C, v.mAxisMasters(EMAC_CSUM_PIPELINE_C+1), EMAC_IPERR_BIT_C, not(r.valid(0)));
161	            axiStreamSetUserBit(INT_EMAC_AXIS_CONFIG_C, v.mAxisMasters(EMAC_CSUM_PIPELINE_C+1), EMAC_EOFE_BIT_C, not(r.valid(0)));
162	         end if;
163	         -- Check if UDP is detected and being checked
164	         if (r.ipv4Det(EMAC_CSUM_PIPELINE_C+1) = '1') and (r.udpDet(EMAC_CSUM_PIPELINE_C+1) = '1') and (udpCsumEn = '1') and (r.fragDet(EMAC_CSUM_PIPELINE_C+1) = '0') then
165	            -- Forward the result of checksum calculation
166	            axiStreamSetUserBit(INT_EMAC_AXIS_CONFIG_C, v.mAxisMasters(EMAC_CSUM_PIPELINE_C+1), EMAC_UDPERR_BIT_C, not(r.valid(1)));
167	            axiStreamSetUserBit(INT_EMAC_AXIS_CONFIG_C, v.mAxisMasters(EMAC_CSUM_PIPELINE_C+1), EMAC_EOFE_BIT_C, not(r.valid(1)));
168	            -- Check for mismatch in IPv4 length with UDP length
169	            if (r.ipv4Len(EMAC_CSUM_PIPELINE_C+1) /= (r.protLen(EMAC_CSUM_PIPELINE_C+1) + 20)) then
170	               -- Set the error flags
171	               axiStreamSetUserBit(INT_EMAC_AXIS_CONFIG_C, v.mAxisMasters(EMAC_CSUM_PIPELINE_C+1), EMAC_UDPERR_BIT_C, '1');
172	               axiStreamSetUserBit(INT_EMAC_AXIS_CONFIG_C, v.mAxisMasters(EMAC_CSUM_PIPELINE_C+1), EMAC_EOFE_BIT_C, '1');
173	            end if;
174	         end if;
175	         -- Check if TCP is detected and being checked
176	         if (r.ipv4Det(EMAC_CSUM_PIPELINE_C+1) = '1') and (r.tcpDet(EMAC_CSUM_PIPELINE_C+1) = '1') and (tcpCsumEn = '1') and (r.fragDet(EMAC_CSUM_PIPELINE_C+1) = '0') then
177	            -- Forward the result of checksum calculation
178	            axiStreamSetUserBit(INT_EMAC_AXIS_CONFIG_C, v.mAxisMasters(EMAC_CSUM_PIPELINE_C+1), EMAC_TCPERR_BIT_C, not(r.valid(1)));
179	            axiStreamSetUserBit(INT_EMAC_AXIS_CONFIG_C, v.mAxisMasters(EMAC_CSUM_PIPELINE_C+1), EMAC_EOFE_BIT_C, not(r.valid(1)));
180	         end if;
181	      end if;
182	
183	      -- State Machine
184	      case r.state is
185	         ----------------------------------------------------------------------
186	         when IDLE_S =>
187	            -- Reset the flags and counter
188	            v.fragDet(0) := '0';
189	            v.eofeDet(0) := '0';
190	            v.ipv4Det(0) := '0';
191	            v.udpDet(0)  := '0';
192	            v.tcpDet(0)  := '0';
193	            v.tcpFlag    := '0';
194	            -- Check for valid data
195	            if (sAxisMaster.tValid = '1') then
196	               -- Move the data
197	               v.mAxisMaster := sAxisMaster;
198	               -- Check for no EOF
199	               if (sAxisMaster.tLast = '0') then
200	                  -- Check for EtherType = IPV4 = 0x0800
201	                  if (sAxisMaster.tData(111 downto 96) = IPV4_TYPE_C) then
202	                     -- Set the flag
203	                     v.ipv4Det(0) := '1';
204	                  end if;
205	                  -- Fill in the IPv4 header checksum
206	                  v.ipv4Hdr(0) := sAxisMaster.tData(119 downto 112);  -- IPVersion + Header length
207	                  v.ipv4Hdr(1) := sAxisMaster.tData(127 downto 120);  -- DSCP and ECN
208	                  -- Next state
209	                  v.state      := IPV4_HDR0_S;
210	               end if;
211	            end if;
212	         ----------------------------------------------------------------------
213	         when IPV4_HDR0_S =>
214	            -- Check for valid data
215	            if (sAxisMaster.tValid = '1') then
216	               -- Move the data
217	               v.mAxisMaster := sAxisMaster;
218	               -- Check for EOF
219	               if (sAxisMaster.tLast = '1') then
220	                  -- Set the error flag if IPv4 is detected and being checked
221	                  axiStreamSetUserBit(INT_EMAC_AXIS_CONFIG_C, v.mAxisMaster, EMAC_IPERR_BIT_C, r.ipv4Det(0));
222	                  -- Next state
223	                  v.state := IDLE_S;
224	               else
225	                  -- Fill in the IPv4 header checksum
226	                  v.ipv4Hdr(2)         := sAxisMaster.tData(7 downto 0);  -- IPV4_Length(15 downto 8)
227	                  v.ipv4Hdr(3)         := sAxisMaster.tData(15 downto 8);  -- IPV4_Length(7 downto 0)
228	                  v.ipv4Hdr(4)         := sAxisMaster.tData(23 downto 16);  -- IPV4_ID(15 downto 8)
229	                  v.ipv4Hdr(5)         := sAxisMaster.tData(31 downto 24);  -- IPV4_ID(7 downto 0)
230	                  v.ipv4Hdr(6)         := sAxisMaster.tData(39 downto 32);  -- Flags(2 downto 0) and Fragment Offsets(12 downto 8)
231	                  v.ipv4Hdr(7)         := sAxisMaster.tData(47 downto 40);  -- Fragment Offsets(7 downto 0)
232	                  v.ipv4Hdr(8)         := sAxisMaster.tData(55 downto 48);  -- Time-To-Live
233	                  v.ipv4Hdr(9)         := sAxisMaster.tData(63 downto 56);  -- Protocol
234	                  v.ipv4Hdr(10)        := sAxisMaster.tData(71 downto 64);  -- IPV4_Checksum(15 downto 8)
235	                  v.ipv4Hdr(11)        := sAxisMaster.tData(79 downto 72);  -- IPV4_Checksum(7 downto 0)
236	                  v.ipv4Hdr(12)        := sAxisMaster.tData(87 downto 80);  -- Source IP Address
237	                  v.ipv4Hdr(13)        := sAxisMaster.tData(95 downto 88);  -- Source IP Address
238	                  v.ipv4Hdr(14)        := sAxisMaster.tData(103 downto 96);  -- Source IP Address
239	                  v.ipv4Hdr(15)        := sAxisMaster.tData(111 downto 104);  -- Source IP Address
240	                  v.ipv4Hdr(16)        := sAxisMaster.tData(119 downto 112);  -- Destination IP Address
241	                  v.ipv4Hdr(17)        := sAxisMaster.tData(127 downto 120);  -- Destination IP Address
242	                  -- Fill in the TCP/UDP checksum
243	                  v.tData(63 downto 0) := sAxisMaster.tData(127 downto 80) & sAxisMaster.tData(63 downto 56) & x"00";
244	                  v.tKeep(7 downto 0)  := (others => '1');
245	
246	                  -- Latch the IPv4 length value
247	                  v.ipv4Len(0)(15 downto 8) := v.ipv4Hdr(2);
248	                  v.ipv4Len(0)(7 downto 0)  := v.ipv4Hdr(3);
249	                  -- Check for UDP protocol
250	                  if (v.ipv4Hdr(9) = UDP_C) then
251	                     v.udpDet(0) := '1';
252	                  end if;
253	                  -- Check for TCP protocol
254	                  if (v.ipv4Hdr(9) = TCP_C) then
255	                     v.tcpDet(0) := '1';
256	                  end if;
257	                  -- Check for fragmentation
258	                  if (v.ipv4Hdr(6)(5) = '1') or (v.ipv4Hdr(6)(4 downto 0) /= 0) or (v.ipv4Hdr(7) /= 0) then
259	                     -- Set the flags
260	                     v.fragDet(0) := '1';
261	                  end if;
262	                  -- Next state
263	                  v.state := IPV4_HDR1_S;
264	               end if;
265	            end if;
266	         ----------------------------------------------------------------------
267	         when IPV4_HDR1_S =>
268	            -- Check for valid data
269	            if (sAxisMaster.tValid = '1') then
270	               -- Move the data
271	               v.mAxisMaster := sAxisMaster;
272	               -- Fill in the TCP/UDP checksum
273	               v.tKeep       := sAxisMaster.tKeep(15 downto 0);
274	               v.tData       := sAxisMaster.tData(127 downto 0);
275	               -- Fill in the IPv4 header checksum
276	               v.ipv4Hdr(18) := sAxisMaster.tData(7 downto 0);  -- Destination IP Address
277	               v.ipv4Hdr(19) := sAxisMaster.tData(15 downto 8);  -- Destination IP Address
278	               -- Check for UDP data with inbound checksum
279	               if (r.ipv4Det(0) = '1') and (r.udpDet(0) = '1') then
280	                  -- Mask off inbound UDP checksum
281	                  v.tData                    := sAxisMaster.tData(127 downto 80) & x"0000" & sAxisMaster.tData(63 downto 0);
282	                  -- Latch the inbound UDP checksum
283	                  v.protCsum(0)(15 downto 8) := sAxisMaster.tData(71 downto 64);
284	                  v.protCsum(0)(7 downto 0)  := sAxisMaster.tData(79 downto 72);
285	                  -- Latch the inbound UDP length
286	                  v.protLen(0)(15 downto 8)  := sAxisMaster.tData(55 downto 48);
287	                  v.protLen(0)(7 downto 0)   := sAxisMaster.tData(63 downto 56);
288	               end if;
289	               if ROCEV2_EN_G and (sAxisMaster.tData(47 downto 32) = x"B712") then
290	                  v.roce(0) := '1';
291	               else
292	                  v.roce(0) := '0';
293	               end if;
294	               -- Track the number of bytes (include IPv4 header offset from previous state)
295	               v.byteCnt := getTKeep(sAxisMaster.tKeep, INT_EMAC_AXIS_CONFIG_C) + 18;
296	               -- Check for EOF
297	               if (sAxisMaster.tLast = '1') then
298	                  -- Next state
299	                  v.state := IDLE_S;
300	               else
301	                  -- Next state
302	                  v.state := MOVE_S;
303	               end if;
304	            end if;
305	         ----------------------------------------------------------------------
306	         when MOVE_S =>
307	            -- Check for valid data
308	            if (sAxisMaster.tValid = '1') then
309	               -- Move the data
310	               v.mAxisMaster := sAxisMaster;
311	               -- Fill in the TCP/UDP checksum
312	               v.tData       := sAxisMaster.tData(127 downto 0);
313	               v.tKeep       := sAxisMaster.tKeep(15 downto 0);
314	               -- Check for TCP data with inbound checksum
315	               if (r.ipv4Det(0) = '1') and (r.tcpDet(0) = '1') and (r.tcpFlag = '0') then
316	                  -- Set the flag
317	                  v.tcpFlag                  := '1';
318	                  -- Calculate TCP length from IPv4 length
319	                  v.protLen(0)               := r.ipv4Len(0) - 20;
320	                  -- Mask off inbound TCP checksum
321	                  v.tData                    := sAxisMaster.tData(127 downto 32) & x"0000" & sAxisMaster.tData(15 downto 0);
322	                  -- Latch the inbound TCP checksum
323	                  v.protCsum(0)(15 downto 8) := sAxisMaster.tData(23 downto 16);
324	                  v.protCsum(0)(7 downto 0)  := sAxisMaster.tData(31 downto 24);
325	               end if;
326	               -- Track the number of bytes
327	               v.byteCnt := r.byteCnt + getTKeep(sAxisMaster.tKeep, INT_EMAC_AXIS_CONFIG_C);
328	               -- Check for EOF
329	               if (sAxisMaster.tLast = '1') or (v.byteCnt > MAX_FRAME_SIZE_C) then
330	                  -- Check for overflow condition
331	                  if (sAxisMaster.tLast = '0') then
332	                     -- Force EOF
333	                     v.mAxisMaster.tLast := '1';
334	                     -- Set the error flag
335	                     axiStreamSetUserBit(INT_EMAC_AXIS_CONFIG_C, v.mAxisMaster, EMAC_EOFE_BIT_C, '1');
336	                     -- Next state
337	                     v.state             := BLOWOFF_S;
338	                  else
339	                     -- Next state
340	                     v.state     := IDLE_S;
341	                     -- Flush the AXIS pipeline
342	                     v.pipeFlush := '1';
343	                  end if;
344	               end if;
345	            end if;
346	         ----------------------------------------------------------------------
347	         when BLOWOFF_S =>
348	            -- Check for a valid EOF
349	            if (sAxisMaster.tValid = '1') and (sAxisMaster.tLast = '1') then
350	               -- Next State
351	               v.state := IDLE_S;
352	            end if;
353	      ----------------------------------------------------------------------
354	      end case;
355	
356	      -- Check for first TUSER on the output AXIS stream
357	      if (axiStreamGetUserBit(INT_EMAC_AXIS_CONFIG_C, v.mAxisMasters(EMAC_CSUM_PIPELINE_C+1), EMAC_SOF_BIT_C, 0) = '1') then
358	         -- Set the fragmentation flag
359	         axiStreamSetUserBit(INT_EMAC_AXIS_CONFIG_C, v.mAxisMasters(EMAC_CSUM_PIPELINE_C+1), EMAC_FRAG_BIT_C, r.fragDet(EMAC_CSUM_PIPELINE_C), 0);
360	      end if;
361	
362	      -- Outputs
363	      mAxisMaster          <= r.mAxisMasters(EMAC_CSUM_PIPELINE_C+1);
364	      mAxisMaster.tDest(0) <= r.roce(EMAC_CSUM_PIPELINE_C);
365	      dbg                  <= dummy;
366	
367	      -- Reset
368	      if (RST_ASYNC_G = false and ethRst = RST_POLARITY_G) then
369	         v := REG_INIT_C;
370	      end if;
371	
372	      -- Register the variable for next clock cycle
373	      rin <= v;
374	
375	   end process comb;
376	
377	   seq : process (ethClk, ethRst) is
378	   begin
379	      if (RST_ASYNC_G and ethRst = RST_POLARITY_G) then
380	         r <= REG_INIT_C after TPD_G;
381	      elsif rising_edge(ethClk) then
382	         r <= rin after TPD_G;
383	      end if;
384	   end process seq;
385	
386	end rtl;
387

