1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description:
5	-- Generic pause frame generator for Ethernet MACs.  This module as acts as
6	-- a gate keeper when the peer has requested a pause period.
7	-------------------------------------------------------------------------------
8	-- This file is part of 'SLAC Firmware Standard Library'.
9	-- It is subject to the license terms in the LICENSE.txt file found in the
10	-- top-level directory of this distribution and at:
11	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
12	-- No part of 'SLAC Firmware Standard Library', including this file,
13	-- may be copied, modified, propagated, or distributed except according to
14	-- the terms contained in the LICENSE.txt file.
15	-------------------------------------------------------------------------------
16	
17	library ieee;
18	use ieee.std_logic_1164.all;
19	use ieee.std_logic_arith.all;
20	use ieee.std_logic_unsigned.all;
21	
22	library surf;
23	use surf.AxiStreamPkg.all;
24	use surf.StdRtlPkg.all;
25	use surf.EthMacPkg.all;
26	
27	entity EthMacTxPause is
28	   generic (
29	      TPD_G           : time                    := 1 ns;
30	      RST_POLARITY_G  : sl                      := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
31	      RST_ASYNC_G     : boolean                 := false;
32	      PAUSE_EN_G      : boolean                 := true;
33	      PAUSE_512BITS_G : natural range 1 to 1024 := 8);
34	   port (
35	      -- Clock and Reset
36	      ethClk       : in  sl;
37	      ethRst       : in  sl;
38	      -- Incoming data from client
39	      sAxisMaster  : in  AxiStreamMasterType;
40	      sAxisSlave   : out AxiStreamSlaveType;
41	      -- Outgoing data to MAC
42	      mAxisMaster  : out AxiStreamMasterType;
43	      mAxisSlave   : in  AxiStreamSlaveType;
44	      -- Flow control input
45	      clientPause  : in  sl;
46	      -- Inputs from pause frame RX
47	      rxPauseReq   : in  sl;
48	      rxPauseValue : in  slv(15 downto 0);
49	      -- Configuration and status
50	      phyReady     : in  sl;
51	      pauseEnable  : in  sl;
52	      pauseTime    : in  slv(15 downto 0);
53	      macAddress   : in  slv(47 downto 0);
54	      pauseTx      : out sl);
55	end EthMacTxPause;
56	
57	architecture rtl of EthMacTxPause is
58	
59	   constant CNT_BITS_C : integer := bitSize(PAUSE_512BITS_G-1);
60	
61	   type StateType is (
62	      IDLE_S,
63	      PAUSE_S,
64	      PASS_S);
65	
66	   type RegType is record
67	      locPauseCnt : slv(15 downto 0);
68	      remPauseCnt : slv(15 downto 0);
69	      txCount     : slv(1 downto 0);
70	      locPreCnt   : slv(CNT_BITS_C-1 downto 0);
71	      remPreCnt   : slv(CNT_BITS_C-1 downto 0);
72	      pauseTx     : sl;
73	      mAxisMaster : AxiStreamMasterType;
74	      sAxisSlave  : AxiStreamSlaveType;
75	      state       : StateType;
76	   end record RegType;
77	
78	   constant REG_INIT_C : RegType := (
79	      locPauseCnt => (others => '0'),
80	      remPauseCnt => (others => '0'),
81	      txCount     => (others => '0'),
82	      locPreCnt   => (others => '0'),
83	      remPreCnt   => (others => '0'),
84	      pauseTx     => '0',
85	      mAxisMaster => AXI_STREAM_MASTER_INIT_C,
86	      sAxisSlave  => AXI_STREAM_SLAVE_INIT_C,
87	      state       => IDLE_S);
88	
89	   signal r   : RegType := REG_INIT_C;
90	   signal rin : RegType;
91	
92	   -- attribute dont_touch      : string;
93	   -- attribute dont_touch of r : signal is "true";
94	
95	begin
96	
97	   U_TxPauseGen : if (PAUSE_EN_G = true) generate
98	
99	      comb : process (clientPause, ethRst, mAxisSlave, pauseEnable, pauseTime,
100	                      phyReady, r, rxPauseReq, rxPauseValue, sAxisMaster) is
101	         variable v : RegType;
102	      begin
103	         -- Latch the current value
104	         v := r;
105	
106	         -- Reset the flags
107	         v.pauseTx    := '0';
108	         v.sAxisSlave := AXI_STREAM_SLAVE_INIT_C;
109	         if (mAxisSlave.tReady = '1') then
110	            v.mAxisMaster.tValid := '0';
111	         end if;
112	
113	         -- Pre-counter, 8 clocks ~= 512 bit times of 10G
114	         v.remPreCnt := r.remPreCnt - 1;
115	         v.locPreCnt := r.locPreCnt - 1;
116	
117	         -- Local pause count tracking
118	         if (pauseEnable = '0') then
119	            v.locPauseCnt := (others => '0');
120	         elsif (rxPauseReq = '1') then
121	            v.locPauseCnt := rxPauseValue;
122	            v.locPreCnt   := (others => '1');
123	         elsif (r.locPauseCnt /= 0) and (r.locPreCnt = 0) then
124	            v.locPauseCnt := r.locPauseCnt - 1;
125	         end if;
126	
127	         -- Remote pause count tracking
128	         if (r.remPauseCnt /= 0) and (r.remPreCnt = 0) then
129	            v.remPauseCnt := r.remPauseCnt - 1;
130	         end if;
131	
132	         -- State Machine
133	         case r.state is
134	            ----------------------------------------------------------------------
135	            when IDLE_S =>
136	               -- Check if we need to transmit pause
137	               if (clientPause = '1') and (r.remPauseCnt = 0) and (pauseEnable = '1') and (phyReady = '1') then
138	                  -- Next state
139	                  v.state := PAUSE_S;
140	               -- Transmit required and not paused by received pause count
141	               elsif (sAxisMaster.tValid = '1') and (r.locPauseCnt = 0) then
142	                  -- Next state
143	                  v.state := PASS_S;
144	               end if;
145	            ----------------------------------------------------------------------
146	            when PAUSE_S =>
147	               --------------------------------------------------------------------------------------------------------------------
148	               -- Refer to https://hasanmansur1.files.wordpress.com/2012/12/ethernet-flow-control-pause-frame-framing-structure.png
149	               --------------------------------------------------------------------------------------------------------------------
150	               -- Check if ready to move data
151	               if (v.mAxisMaster.tValid = '0') then
152	                  -- Reset the bus to defaults
153	                  v.mAxisMaster        := AXI_STREAM_MASTER_INIT_C;
154	                  -- Performing a write operation
155	                  v.mAxisMaster.tValid := '1';
156	                  -- Increment the counter
157	                  v.txCount            := r.txCount + 1;
158	                  -- Check the flag
159	                  if (r.txCount = 0) then
160	                     -- DST MAC (Pause MAC Address)
161	                     v.mAxisMaster.tData(47 downto 0)    := x"01_00_00_C2_80_01";
162	                     -- SRC MAC (NULL MAC address)
163	                     v.mAxisMaster.tData(95 downto 48)   := x"00_00_00_00_00_00";
164	                     -- MAC Control Type
165	                     v.mAxisMaster.tData(111 downto 96)  := x"08_88";
166	                     -- Pause Op-code
167	                     v.mAxisMaster.tData(127 downto 112) := x"01_00";  -- 2 bytes
168	                  elsif (r.txCount = 1) then
169	                     -- Pause length
170	                     v.mAxisMaster.tData(7 downto 0)    := pauseTime(15 downto 8);  -- 1 bytes
171	                     v.mAxisMaster.tData(15 downto 8)   := pauseTime(7 downto 0);  -- 1 bytes
172	                     -- Zero Padding
173	                     v.mAxisMaster.tData(127 downto 16) := (others => '0');  -- 14 bytes
174	                  elsif (r.txCount = 2) then
175	                     -- Zero Padding
176	                     v.mAxisMaster.tData(127 downto 0) := (others => '0');
177	                     v.mAxisMaster.tKeep(15 downto 0)  := x"FFFF";  -- 16 bytes
178	                  else
179	                     -- Zero Padding
180	                     v.mAxisMaster.tData(127 downto 0) := (others => '0');
181	                     v.mAxisMaster.tKeep(15 downto 0)  := x"0FFF";  -- 12 bytes (Fixed frame size = 46 bytes)
182	                     -- Set EOF
183	                     v.mAxisMaster.tLast               := '1';
184	                     -- Latch the Pause time
185	                     v.remPauseCnt                     := '0' & pauseTime(15 downto 1);  -- retransmit if half of pauseTime time
186	                     v.remPreCnt                       := (others => '1');
187	                     v.pauseTx                         := '1';
188	                     -- Reset the counter
189	                     v.txCount                         := (others => '0');
190	                     -- Next state
191	                     v.state                           := IDLE_S;
192	                  end if;
193	               end if;
194	            ----------------------------------------------------------------------
195	            when PASS_S =>
196	               -- Check if ready to move data
197	               if (v.mAxisMaster.tValid = '0') and (sAxisMaster.tValid = '1') then
198	                  -- Accept the data
199	                  v.sAxisSlave.tReady := '1';
200	                  -- Move the data
201	                  v.mAxisMaster       := sAxisMaster;
202	                  -- Check for EOF
203	                  if (sAxisMaster.tLast = '1') then
204	                     -- Next state
205	                     v.state := IDLE_S;
206	                  end if;
207	               end if;
208	         ----------------------------------------------------------------------
209	         end case;
210	
211	         -- Combinatorial outputs before the reset
212	         sAxisSlave <= v.sAxisSlave;
213	
214	         -- Reset
215	         if (RST_ASYNC_G = false and ethRst = RST_POLARITY_G) then
216	            v := REG_INIT_C;
217	         end if;
218	
219	         -- Register the variable for next clock cycle
220	         rin <= v;
221	
222	         -- Registered Outputs
223	         mAxisMaster <= r.mAxisMaster;
224	         pauseTx     <= r.pauseTx;
225	
226	      end process;
227	
228	      seq : process (ethClk, ethRst) is
229	      begin
230	         if (RST_ASYNC_G and ethRst = RST_POLARITY_G) then
231	            r <= REG_INIT_C after TPD_G;
232	         elsif rising_edge(ethClk) then
233	            r <= rin after TPD_G;
234	         end if;
235	      end process seq;
236	
237	   end generate;
238	
239	   U_BypTxPause : if (PAUSE_EN_G = false) generate
240	      mAxisMaster <= sAxisMaster;
241	      sAxisSlave  <= mAxisSlave;
242	      pauseTx     <= '0';
243	   end generate;
244	
245	end rtl;
246

